// Site contract: { event, agent, phone, timestamp } nested under $json.body
const body = ($input.first().json.body) || $input.first().json || {};
let raw = (body.phone || '').toString().trim();
let digits = raw.replace(/[^\d+]/g, '');
let to = '';
if (digits.startsWith('+')) to = digits;
else if (digits.startsWith('0')) to = '+61' + digits.slice(1);
else if (digits.startsWith('61')) to = '+' + digits;
else if (digits.length >= 8) to = '+' + digits;
const valid = /^\+\d{8,15}$/.test(to);
return [{ json: {
  valid, to,
  agentName: (body.agent || 'darl').toString().trim(),
  event: body.event || 'voice_callback_requested',
  timestamp: body.timestamp || new Date().toISOString(),
  raw_phone: raw,
  source: 'goodai-mate-site'
}}];

// Trillet GET /agents returns an array -> n8n splits to one item per agent
const agents = $input.all().map(i => i.json).filter(a => a && a._id);
const want = ($('Normalize Phone').first().json.agentName || '').toLowerCase();

let match = agents.find(a => (a.name || '').toLowerCase() === want)
         || agents.find(a => (a.name || '').toLowerCase().includes(want));

if (!match) {
  const names = agents.map(a => a.name).join(', ') || '(none returned)';
  throw new Error('No Trillet agent matching "' + want + '". Available: ' + names);
}

const n = $('Normalize Phone').first().json;
return [{ json: {
  call_agent_id: match._id,
  agent_name: match.name,
  to: n.to,
  agentName: n.agentName,
  event: n.event,
  timestamp: n.timestamp,
  raw_phone: n.raw_phone,
  source: n.source
}}];
